/**
 * Webhook notification handler for order lifecycle events.
 *
 * Subscribes to EventBus events and delivers webhook HTTP POST
 * callbacks to registered URLs. Uses the same EventBus pattern
 * as NotificationService and EmailNotificationHandler for consistency.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { AppEvent, EventType, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  secret?: string;
  registeredAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  success: boolean;
  statusCode: number;
  deliveredAt: Date;
}

let nextRegistrationId = 1;
let nextDeliveryId = 1;

function generateRegistrationId(): string {
  return `webhook-${String(nextRegistrationId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextRegistrationId = 1;
  nextDeliveryId = 1;
}

export class WebhookNotificationHandler {
  private logger = new Logger('WebhookNotificationHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleEvent(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleEvent(event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  registerWebhook(url: string, eventType: EventType, secret?: string): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateRegistrationId(),
      url,
      eventType,
      secret,
      registeredAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${webhookId}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Handle an event by delivering to all matching webhooks.
   */
  private handleEvent(event: AppEvent): void {
    const matchingWebhooks = this.registrations.filter(
      (r) => r.eventType === event.type,
    );

    for (const webhook of matchingWebhooks) {
      this.deliverWebhook(webhook, event);
    }
  }

  /**
   * Deliver a webhook payload (in-memory simulation for this demo).
   */
  private deliverWebhook(webhook: WebhookRegistration, event: AppEvent): void {
    const payload = this.buildPayload(event);

    const delivery: WebhookDelivery = {
      id: generateDeliveryId(),
      webhookId: webhook.id,
      url: webhook.url,
      eventType: event.type,
      payload,
      success: true,
      statusCode: 200,
      deliveredAt: new Date(),
    };

    this.deliveries.push(delivery);
    this.logger.info(
      `Webhook delivered: ${delivery.id} to ${webhook.url} for ${event.type}`,
    );
  }

  /**
   * Build the webhook payload from an event.
   */
  private buildPayload(event: AppEvent): Record<string, unknown> {
    if (event.type === 'order:created') {
      const e = event as OrderCreatedEvent;
      return {
        event: e.type,
        timestamp: e.timestamp.toISOString(),
        data: {
          orderId: e.order.id,
          userId: e.order.userId,
          items: e.order.items,
          total: e.order.total,
          status: e.order.status,
        },
      };
    }

    if (event.type === 'order:status-changed') {
      const e = event as OrderStatusChangedEvent;
      return {
        event: e.type,
        timestamp: e.timestamp.toISOString(),
        data: {
          orderId: e.order.id,
          userId: e.order.userId,
          previousStatus: e.previousStatus,
          newStatus: e.newStatus,
        },
      };
    }

    return {
      event: event.type,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookNotificationHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-notification-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    resetWebhookIdCounters();
    handler = new WebhookNotificationHandler(eventBus);
  });

  describe('webhook registration', () => {
    it('should register a webhook for an event type', () => {
      const reg = handler.registerWebhook(
        'https://example.com/hook',
        'order:created',
      );

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.registeredAt).toBeInstanceOf(Date);
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.registerWebhook(
        'https://example.com/hook',
        'order:created',
        'my-secret',
      );

      expect(reg.secret).toBe('my-secret');
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');
      handler.registerWebhook('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook(
        'https://example.com/hook',
        'order:created',
      );

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });

    it('should assign incrementing IDs', () => {
      const r1 = handler.registerWebhook('https://a.com', 'order:created');
      const r2 = handler.registerWebhook('https://b.com', 'order:created');

      expect(r1.id).toBe('webhook-0001');
      expect(r2.id).toBe('webhook-0002');
    });
  });

  describe('order:created webhook delivery', () => {
    it('should deliver to registered webhooks when order is created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.statusCode).toBe(200);
    });

    it('should include order data in the payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-42',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 5 },
          ],
          total: 15,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const payload = handler.getDeliveries()[0]!.payload;
      expect(payload['event']).toBe('order:created');
      const data = payload['data'] as Record<string, unknown>;
      expect(data['orderId']).toBe('order-42');
      expect(data['total']).toBe(15);
      expect(data['status']).toBe('pending');
    });

    it('should not deliver to webhooks registered for other event types', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('order:status-changed webhook delivery', () => {
    const makeStatusEvent = (
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent => ({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    it('should deliver to registered webhooks on status change', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.eventType).toBe('order:status-changed');
    });

    it('should include status change data in the payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const payload = handler.getDeliveries()[0]!.payload;
      expect(payload['event']).toBe('order:status-changed');
      const data = payload['data'] as Record<string, unknown>;
      expect(data['previousStatus']).toBe('confirmed');
      expect(data['newStatus']).toBe('shipped');
      expect(data['orderId']).toBe('order-1');
    });

    it('should deliver to multiple webhooks for the same event type', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:status-changed');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(2);
      const urls = handler.getDeliveries().map((d) => d.url);
      expect(urls).toContain('https://a.com/hook');
      expect(urls).toContain('https://b.com/hook');
    });
  });

  describe('delivery management', () => {
    it('should count deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveryCount()).toBe(1);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:status-changed');
      handler.registerWebhook('https://b.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(reg1.id)[0]?.url).toBe('https://a.com/hook');
    });

    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      handler.clearAll();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });

    it('should not deliver after webhook is unregistered', async () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:status-changed');
      handler.unregisterWebhook(reg.id);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notificationService = new NotificationService(eventBus);

      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getDeliveryCount()).toBe(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should work alongside EmailNotificationHandler on the same EventBus', async () => {
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email-notification-handler.js'
      );
      const emailHandler = new EmailNotificationHandler(eventBus);

      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(handler.getDeliveryCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
    });
  });
});
